// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with the order available as the global "order" variable, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Inject the entire order as a global "order" variable
	// This avoids issues with order keys that are not valid JS identifiers
	// and prevents overwriting built-in JS globals
