	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Get the exported value
	val := result.Export()

	// Check for undefined/null
	if val == nil {
		return 0.0, fmt.Errorf("script returned undefined or null, expected a number")
	}

	// Use reflection to handle all numeric types and convert to float64
	rv := reflect.ValueOf(val)
	switch rv.Kind() {
