// deepCopyMap creates a deep copy of a map[string]interface{} to prevent modification of the original
func deepCopyMap(original map[string]interface{}) map[string]interface{} {
	copy := make(map[string]interface{}, len(original))
	for k, v := range original {
		copy[k] = deepCopyValue(v)
	}
	return copy
}

// deepCopyValue recursively copies values to prevent modification of the original data
func deepCopyValue(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		return deepCopyMap(val)
	case []interface{}:
		sliceCopy := make([]interface{}, len(val))
		for i, elem := range val {
			sliceCopy[i] = deepCopyValue(elem)
		}
		return sliceCopy
	// Basic types are passed by value, no need to copy
	case int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64, string, bool, nil:
		return val
	default:
		// Fallback to JSON marshaling/unmarshaling for unsupported types
		data, err := json.Marshal(val)
		if err != nil {
			return val // Return original if marshal fails
		}
		var copied interface{}
		if err := json.Unmarshal(data, &copied); err != nil {
			return val // Return original if unmarshal fails
		}
		return copied
	}
}

