	vm := goja.New()

	// Disable potentially dangerous globals to prevent dynamic code execution
	_ = vm.Set("eval", goja.Undefined())
	_ = vm.Set("Function", goja.Undefined())

	// Deep copy the order to prevent the script from modifying the original data
	copiedOrder := deepCopyMap(order)

