	if err := vm.Set("order", copiedOrder); err != nil {
		return 0.0, fmt.Errorf("failed to inject order into VM: %w", err)
	}

	// Set up a timeout to prevent infinite loops or long-running scripts (DoS protection)
	ctx, cancel := context.WithTimeout(context.Background(), 500*time.Millisecond)
	defer cancel()

	type runResult struct {
		value goja.Value
		err   error
	}
	resultCh := make(chan runResult, 1)

	// Run the script in a goroutine to allow interruption on timeout
	go func() {
		val, err := vm.RunString(script)
		resultCh <- runResult{value: val, err: err}
	}()

	select {
	case <-ctx.Done():
		// Interrupt the VM to stop script execution
		vm.Interrupt(fmt.Errorf("execution timed out"))
		return 0.0, fmt.Errorf("script execution timed out: %w", ctx.Err())
	case res := <-resultCh:
