// deepCopy creates a deep copy of common JSON-serializable types to prevent
// the JavaScript script from modifying the original order data.
func deepCopy(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		copied := make(map[string]interface{}, len(val))
		for k, v := range val {
			copied[k] = deepCopy(v)
		}
		return copied
	case []interface{}:
		copied := make([]interface{}, len(val))
		for i, v := range val {
			copied[i] = deepCopy(v)
		}
		return copied
	// Basic immutable types
	case int, int8, int16, int32, int64,
		uint, uint8, uint16, uint32, uint64, uintptr,
		float32, float64,
		bool, string,
		complex64, complex128:
		return val
	case nil:
		return nil
	default:
		// For unsupported types, return as-is (order should only contain JSON types)
		return val
	}
}

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with the order available as a global "order" variable, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Deep copy the order to prevent script modifications to the original data
	copiedOrder := deepCopy(order).(map[string]interface{})

	// Inject the entire order as a single global "order" variable (safer than individual fields)
	if err := vm.Set("order", copiedOrder); err != nil {
		return 0.0, fmt.Errorf("failed to inject order data: %w", err)
	}

	// Execute the JavaScript script
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution failed: %w", err)
	}

	// Convert result to float64
	var discount float64
	if err := vm.ExportTo(result, &discount); err != nil {
		return 0.0, fmt.Errorf("script must return a numeric value: %w", err)
	}

	return discount, nil
}

